import{_ as t,o as i,c as r,ag as l}from"./chunks/framework.B9unkguw.js";const u=JSON.parse('{"title":"3D 视图","description":"","frontmatter":{},"headers":[],"relativePath":"zh/qgc-user-guide/viewer_3d/viewer_3d.md","filePath":"zh/qgc-user-guide/viewer_3d/viewer_3d.md"}'),a={name:"zh/qgc-user-guide/viewer_3d/viewer_3d.md"};function n(o,e,s,h,g,d){return i(),r("div",null,e[0]||(e[0]=[l('<h1 id="_3d-视图" tabindex="-1">3D 视图 <a class="header-anchor" href="#_3d-视图" aria-label="Permalink to &quot;3D 视图&quot;">​</a></h1><p>3D视图用于视觉和监测载具、环境以及计划在3D中执行的任务。 <a href="./../fly_view/fly_view.html">飞行视图</a> 中的大部分功能在3D视图中同样可用。</p><p>您可以使用它：</p><ul><li>从OpenStreetMap 网站(.osm 文件)下载的任何感兴趣区域导入和显示3D映射图。</li><li>在 3D 中显示车辆和它的任务。</li><li>以及<a href="./../fly_view/fly_view.html">飞行视图</a>的大多数功能，包括： <ul><li>Run an automated <a href="./../fly_view/hud.html#preflight_checklist">pre-flight checklist</a>.</li><li>把载具解锁(或检查它为什么不会解锁)。</li><li>Control missions: <a href="./../fly_view/hud.html#start_mission">start</a>, <a href="./../fly_view/hud.html#continue_mission">continue</a>, <a href="./../fly_view/hud.html#pause">pause</a>, and <a href="./../fly_view/hud.html#resume_mission">resume</a>.</li><li>Guide the vehicle to <a href="./../fly_view/hud.html#arm">arm</a>/<a href="./../fly_view/hud.html#disarm">disarm</a>/<a href="./../fly_view/hud.html#emergency_stop">emergency stop</a>, <a href="./../fly_view/hud.html#takeoff">takeoff</a>/<a href="./../fly_view/hud.html#land">land</a>, <a href="./../fly_view/hud.html#change_altitude">change altitude</a>, and <a href="./../fly_view/hud.html#rtl">return/RTL</a>.</li><li>在地图视图和视频视图之间切换(如果可用)</li><li>显示当前载具的视频、飞行任务、遥测和其他信息，同时在已连接的载具之间切换。</li></ul></li></ul><h1 id="界面概述" tabindex="-1">界面概述 <a class="header-anchor" href="#界面概述" aria-label="Permalink to &quot;界面概述&quot;">​</a></h1><p>The main elements of the 3D View are the same as the <a href="./../fly_view/fly_view.html">Fly View</a>, with an added 3D environment.</p><p><strong>Enabling the 3D View:</strong> The 3D View is disabled by default. To enable it, go to <strong>Settings &gt; Fly View</strong>, and under the <strong>3D View</strong> settings group, toggle the <strong>Enabled</strong> switch.</p><p>To open the 3D View, when you are in the <a href="./../fly_view/fly_view.html">Fly View</a>, select the 3D View icon from the toolbar on the left.</p><p>打开3D视图后，您可以使用鼠标或触摸屏来导航3D环境：</p><ul><li><p><strong>鼠标：</strong></p><ul><li><strong>要水平和垂直移动</strong>：按住鼠标左键，然后移动光标。</li><li><strong>要旋转</strong>：按住鼠标右键，然后移动光标。</li><li><strong>放大</strong>：使用鼠标滚轮\\中键。</li></ul></li><li><p><strong>触摸屏:</strong></p><ul><li><strong>要水平和垂直移动</strong>：使用单指，然后点击并移动您的手指。</li><li><strong>要旋转</strong>：使用两个手指，然后点击并移动你的手指，同时将它们保持在一起。</li><li><strong>要缩放</strong>：使用双指的粉丝并移动到一起或分别缩放。</li></ul></li></ul><p>若要在三维查看器中可视化特定区域的3D地图，您必须下载。 从 <a href="https://www.openstreetmap.org/#map=16/47.3964/8.5498" target="_blank" rel="noreferrer">OpenStreetMap</a>网站上的sm 文件，然后通过 <strong>3D View</strong> 的设置导入。 更多关于<strong>3D View</strong> 设置的详细信息可在下一节找到。</p><h1 id="设置" tabindex="-1">设置 <a class="header-anchor" href="#设置" aria-label="Permalink to &quot;设置&quot;">​</a></h1><p>您可以在 <strong>应用程序设置</strong> -&gt;<strong>Fly View</strong> 标签在 <strong>3D View</strong> 设置组中更改3D 视图的设置。 以下属性可以在 3D 视图设置组中修改：</p><ul><li><strong>启用</strong>：要启用或禁用3D视图。</li><li><strong>3D地图文件</strong>：在QGC中可视化感兴趣区域的.osm文件的路径。 可以点击 <strong>选择文件</strong> 按钮上传.osm 文件。 要清除以前加载的 .osm 文件的3D 视图，您可以点击<strong>清除</strong> 按钮。</li><li><strong>建筑物平均楼层高度</strong>：此参数决定建筑物每层的高度，因为在.osm文件中，建筑物高度有时是按楼层来指定的。</li><li><strong>载具高度偏差</strong>：这是指载具及其任务的高度相对于地面的偏差。 在飞行器飞控估算的高度存在偏差的情况下，这很有用，因为3D视图目前使用的是相对高度。</li></ul>',14)]))}const _=t(a,[["render",n]]);export{u as __pageData,_ as default};
